    #[test]
    fn test_take_all_picks_up_every_room_item() {
        let mut state = create_test_exploration_state();
        let room_item_ids = vec![990_u32, 991_u32];
        for (item_id, item_name) in [(990_u32, "Torch"), (991_u32, "Rope")].into_iter() {
            state.world.items.insert(
                item_id,
                state::Item {
                    id: item_id,
                    name: item_name.to_string(),
                    description: format!("A {}.", item_name.to_lowercase()),
                    item_type: state::ItemType::Misc,
                    location: Some(state.current_location),
                    carried_by_player: false,
                    charges_remaining: None,
                },
            );
        }
        state
            .world
            .locations
            .get_mut(&state.current_location)
            .unwrap()
            .items = room_item_ids.clone();

        let state_json = serde_json::to_string(&state).unwrap();
        let output = process_input(&state_json, "take all");
        assert!(
            output
                .text
                .iter()
                .any(|line| line.contains("pick up everything")),
            "Expected bulk pickup narration. Got: {:?}",
            output.text
        );

        let new_state: GameState = serde_json::from_str(&output.state_json).unwrap();
        assert!(
            new_state.world.locations[&new_state.current_location]
                .items
                .is_empty(),
            "Room items should be cleared after take all"
        );
        for item_id in room_item_ids {
            assert!(
                new_state.character.inventory.contains(&item_id),
                "Inventory should contain picked up item {}",
                item_id
            );
            assert!(
                new_state.world.items[&item_id].carried_by_player,
                "Item {} should be marked carried by player",
                item_id
            );
        }
    }

