    fn give_consumable_to_player(
        state: &mut GameState,
        name: &str,
        description: &str,
        effect: &str,
    ) -> u32 {
        let item_id = (state.world.items.len() as u32) + 1000;
        let item = state::Item {
            id: item_id,
            name: name.to_string(),
            description: description.to_string(),
            item_type: state::ItemType::Consumable {
                effect: effect.to_string(),
            },
            location: None,
            carried_by_player: true,
            charges_remaining: None,
        };
        state.world.items.insert(item_id, item);
        state.character.inventory.push(item_id);
        item_id
    }

