    #[test]
    fn test_map_command_multi_room_with_mixed_exits() {
        let mut state = create_test_exploration_state();

        let current_id = state.current_location;
        let discovered_id = 998;
        let undiscovered_id = 999;

        // Modify current location exits
        if let Some(loc) = state.world.locations.get_mut(&current_id) {
            loc.exits.insert(types::Direction::North, discovered_id);
            loc.exits.insert(types::Direction::East, undiscovered_id);
            loc.location_type = state::LocationType::Ruins;
            loc.light_level = state::LightLevel::Bright;
        }

        // Create discovered neighbor
        state.world.locations.insert(
            discovered_id,
            state::Location {
                id: discovered_id,
                name: "Guard Post".to_string(),
                description: "A guarded post.".to_string(),
                location_type: state::LocationType::Room,
                exits: {
                    let mut m = HashMap::new();
                    m.insert(types::Direction::South, current_id);
                    m
                },
                npcs: vec![],
                items: vec![],
                triggers: vec![],
                light_level: state::LightLevel::Dim,
                room_features: vec![],
            },
        );
        state.discovered_locations.insert(discovered_id);

        // Create undiscovered neighbor (exists but NOT in discovered_locations)
        state.world.locations.insert(
            undiscovered_id,
            state::Location {
                id: undiscovered_id,
                name: "Secret Vault".to_string(),
                description: "A hidden vault.".to_string(),
                location_type: state::LocationType::Cave,
                exits: {
                    let mut m = HashMap::new();
                    m.insert(types::Direction::West, current_id);
                    m
                },
                npcs: vec![],
                items: vec![],
                triggers: vec![],
                light_level: state::LightLevel::Dark,
                room_features: vec![],
            },
        );

        let state_json = serde_json::to_string(&state).unwrap();
        let output = process_input(&state_json, "map");

        // Current location shows with * marker, type, and light
        let current_line = output
            .text
            .iter()
            .find(|t| t.starts_with("*"))
            .expect("Should have current location marker");
        assert!(
            current_line.contains("[Ruins]") && current_line.contains("(Bright)"),
            "Current location should show [Ruins] (Bright), got: {:?}",
            current_line
        );

        // Guard Post shows with - marker, type, and light
        let guard_line = output
            .text
            .iter()
            .find(|t| t.starts_with("-") && t.contains("Guard Post"));
        assert!(
            guard_line.is_some(),
            "Discovered non-current location should show with '-' marker, got: {:?}",
            output.text
        );
        let guard_line = guard_line.unwrap();
        assert!(
            guard_line.contains("[Room]") && guard_line.contains("(Dim)"),
            "Guard Post should show [Room] (Dim), got: {:?}",
            guard_line
        );

        // Exit lines under current location
        let exit_north = output
            .text
            .iter()
            .any(|t| t.contains("north") && t.contains("Guard Post"));
        assert!(
            exit_north,
            "North exit should show 'Guard Post' (discovered), got: {:?}",
            output.text
        );

        let exit_east = output
            .text
            .iter()
            .any(|t| t.contains("east") && t.contains("Undiscovered"));
        assert!(
            exit_east,
            "East exit should show 'Undiscovered', got: {:?}",
            output.text
        );
    }

    #[test]
    fn test_world_generation_seeds_objectives() {
        // Complete a full character creation flow and verify objectives are seeded
        let output = new_game(42, false);
        let output = process_input(&output.state_json, "1"); // race
        let output = process_input(&output.state_json, "Fighter"); // class
        let output = process_input(&output.state_json, "1"); // background: Acolyte
        let output = process_input(&output.state_json, "default"); // origin feat
        let output = process_input(&output.state_json, "2"); // ability pattern
        let output = process_input(&output.state_json, "1"); // standard array
        let output = process_input(&output.state_json, "15 14 13 12 10 8"); // scores
        let output = process_input(&output.state_json, "1 2"); // skills
        let output = process_input(&output.state_json, "5"); // alignment: Neutral
        let output = process_input(&output.state_json, "TestHero"); // name

        let state: GameState = serde_json::from_str(&output.state_json).unwrap();
        assert!(matches!(state.game_phase, GamePhase::Exploration));
        assert!(
            !state.progress.objectives.is_empty(),
            "Should have at least one objective after world generation"
        );
        assert_eq!(
            state.progress.objectives.len(),
            state.progress.objective_triggers.len(),
            "objectives and objective_triggers should have same length"
        );

        // Verify the objective references a real entity
        let obj = &state.progress.objectives[0];
        assert!(!obj.title.is_empty());
        assert!(!obj.description.is_empty());
        assert!(!obj.completed);

        match &state.progress.objective_triggers[0] {
            state::ObjectiveType::DefeatNpc(npc_id) => {
                assert!(
                    state.world.npcs.contains_key(npc_id),
                    "DefeatNpc objective should reference an existing NPC"
                );
                let npc = &state.world.npcs[npc_id];
                assert!(
                    obj.title.contains(&npc.name),
                    "Objective title should contain NPC name: {} not in {}",
                    npc.name,
                    obj.title
                );
            }
            state::ObjectiveType::FindItem(item_id) => {
                assert!(
                    state.world.items.contains_key(item_id),
                    "FindItem objective should reference an existing item"
                );
            }
        }
    }

