    #[test]
    fn test_ritual_cast_of_ritual_spell_succeeds_without_slot() {
        // Wizard learns Detect Magic (ritual, concentration) and casts it
        // as a ritual in exploration.
        let mut state = create_test_wizard_state();
        state
            .character
            .known_spells
            .push("Detect Magic".to_string());
        let slots_before = state.character.spell_slots_remaining.clone();
        let state_json = serde_json::to_string(&state).unwrap();
        let output = process_input(&state_json, "cast detect magic ritual");
        let text = output.text.join("\n");
        assert!(
            text.to_lowercase().contains("ritual"),
            "Expected ritual narration. Got:\n{}",
            text
        );
        let new_state: GameState = serde_json::from_str(&output.state_json).unwrap();
        // Slot unchanged on ritual path.
        assert_eq!(
            new_state.character.spell_slots_remaining, slots_before,
            "Ritual casting must not consume a spell slot"
        );
        assert_eq!(
            new_state.character.class_features.concentration_spell,
            Some("Detect Magic".to_string()),
            "Concentration ritual spells should still start concentration"
        );
    }

    #[test]
    fn test_mage_armor_in_exploration_raises_ac_and_uses_slot() {
        let mut state = create_test_wizard_state();
        state.character.known_spells.push("Mage Armor".to_string());
        state
            .character
            .class_features
            .prepared_spells
            .push("Mage Armor".to_string());
        let ac_before = equipment::calculate_ac(&state.character, &state.world.items);
        let slots_before = state.character.spell_slots_remaining.clone();
        let state_json = serde_json::to_string(&state).unwrap();

        let output = process_input(&state_json, "cast mage armor");
        let text = output.text.join(" ");
        assert!(
            text.to_lowercase().contains("base ac is now 13")
                || text.to_lowercase().contains("protective weave"),
            "Expected mage armor narration. Got: {:?}",
            output.text
        );

        let new_state: GameState = serde_json::from_str(&output.state_json).unwrap();
        let ac_after = equipment::calculate_ac(&new_state.character, &new_state.world.items);
        assert!(
            ac_after > ac_before,
            "Mage Armor should raise AC. Before: {}, after: {}",
            ac_before,
            ac_after
        );
        assert_eq!(
            new_state.character.spell_slots_remaining[0],
            slots_before[0] - 1,
            "Mage Armor should consume one level-1 slot"
        );
        assert_eq!(
            new_state.character.class_features.mage_armor_until_minutes,
            Some(8 * 60),
            "Mage Armor should persist for 8 in-world hours from cast time"
        );
    }

