    #[test]
    fn test_attune_cap_blocks_fourth_attunement() {
        use equipment::magic::{Rarity, WondrousEffect};
        let mut state = create_test_exploration_state();
        let a = give_wondrous_to_player(
            &mut state,
            "Cloak of Protection",
            WondrousEffect::CloakOfProtection,
            Rarity::Uncommon,
            true,
        );
        let b = give_wondrous_to_player(
            &mut state,
            "Ring of Protection",
            WondrousEffect::RingOfProtection,
            Rarity::Rare,
            true,
        );
        let c = give_wondrous_to_player(
            &mut state,
            "Gauntlets of Ogre Power",
            WondrousEffect::GauntletsOfOgrePower,
            Rarity::Uncommon,
            true,
        );
        // Fourth item — adding should fail.
        let d = give_wondrous_to_player(
            &mut state,
            "Belt of Giant Strength",
            WondrousEffect::BeltOfGiantStrength(21),
            Rarity::Rare,
            true,
        );
        // Pre-fill the attuned vec with the first three IDs (skip actually running attune commands for brevity).
        state.character.attuned_items = vec![a, b, c];

        let state_json = serde_json::to_string(&state).unwrap();
        let output = process_input(&state_json, "attune belt");
        let new_state: GameState = serde_json::from_str(&output.state_json).unwrap();
        assert!(
            !new_state.character.attuned_items.contains(&d),
            "Fourth attunement must not be added. Got: {:?}",
            new_state.character.attuned_items
        );
        assert!(
            output
                .text
                .iter()
                .any(|t| t.to_lowercase().contains("already attuned")
                    || t.to_lowercase().contains("unattune")
                    || t.to_lowercase().contains("max")),
            "Expected cap-exceeded narration. Got: {:?}",
            output.text
        );
    }

