    // Hypothesis: A merchant NPC that is initially Friendly loses its disposition
    // and becomes hostile (triggering combat) when the player revisits the room
    // via an alternate path. The bug occurs because the at-least-one-hostile
    // guarantee in generate_world() can promote a Merchant NPC to Hostile when
    // no Guard NPC exists and the Merchant has the lowest ID.
    #[test]
    fn test_merchant_npc_stays_friendly_on_revisit_via_alternate_path() {
        use crate::types::Direction;

        let mut state = create_test_exploration_state();

        // === Build a 3-room topology ===
        //
        //   Room A (start, id=900)
        //     |  North -> Room B (id=901)
        //     |  East  -> Room C (id=902)
        //
        //   Room B (id=901) — merchant room
        //     |  South -> Room A (id=900)
        //     |  East  -> Room C (id=902)
        //
        //   Room C (id=902)
        //     |  West  -> Room A (id=900)
        //     |  West  -> Room B (id=901)  (alternate entry to merchant room)
        //
        // Actually Room C needs two westward exits, which isn't possible with
        // Direction as the key. Let's use North from C to B instead.
        //
        //   Room C (id=902)
        //     |  West  -> Room A (id=900)
        //     |  North -> Room B (id=901)

        let room_a_id = 900u32;
        let room_b_id = 901u32;
        let room_c_id = 902u32;

        // Room A
        state.world.locations.insert(room_a_id, state::Location {
            id: room_a_id,
            name: "Starting Hall".to_string(),
            description: "A plain stone hall.".to_string(),
            location_type: state::LocationType::Room,
            exits: {
                let mut m = HashMap::new();
                m.insert(Direction::North, room_b_id);
                m.insert(Direction::East, room_c_id);
                m
            },
            npcs: vec![],
            items: vec![],
            triggers: vec![],
            light_level: state::LightLevel::Bright,
            room_features: vec![],
        });

        // Room B — merchant room
        state.world.locations.insert(room_b_id, state::Location {
            id: room_b_id,
            name: "Merchant Alcove".to_string(),
            description: "A cozy alcove with trade goods.".to_string(),
            location_type: state::LocationType::Room,
            exits: {
                let mut m = HashMap::new();
                m.insert(Direction::South, room_a_id);
                m.insert(Direction::East, room_c_id);
                m
            },
            npcs: vec![],  // will push merchant NPC id below
            items: vec![],
            triggers: vec![],
            light_level: state::LightLevel::Bright,
            room_features: vec![],
        });

        // Room C — alternate corridor
        state.world.locations.insert(room_c_id, state::Location {
            id: room_c_id,
            name: "Side Corridor".to_string(),
            description: "A narrow corridor.".to_string(),
            location_type: state::LocationType::Corridor,
            exits: {
                let mut m = HashMap::new();
                m.insert(Direction::West, room_a_id);
                m.insert(Direction::North, room_b_id);
                m
            },
            npcs: vec![],
            items: vec![],
            triggers: vec![],
            light_level: state::LightLevel::Dim,
            room_features: vec![],
        });

        // Add a Friendly Merchant NPC in Room B
        let merchant_npc_id = 500u32;
        state.world.npcs.insert(merchant_npc_id, state::Npc {
            id: merchant_npc_id,
            name: "Greta the Merchant".to_string(),
            role: state::NpcRole::Merchant,
            disposition: state::Disposition::Friendly,
            dialogue_tags: vec!["trade".to_string(), "goods".to_string()],
            location: room_b_id,
            combat_stats: None,
            conditions: vec![],
        });
        state.world.locations.get_mut(&room_b_id).unwrap().npcs.push(merchant_npc_id);

        // Set the player at Room A
        state.current_location = room_a_id;
        state.discovered_locations = [room_a_id].into_iter().collect();

        // === Visit 1: Go North from A to B ===
        let state_json = serde_json::to_string(&state).unwrap();
        let output1 = process_input(&state_json, "go north");

        // Should NOT trigger combat
        let text1 = output1.text.join(" ");
        assert!(
            !text1.contains("initiative") && !text1.contains("VICTORY") && !text1.contains("Your turn"),
            "First visit: merchant room should NOT trigger combat. Got: {:?}",
            output1.text
        );
        // Should mention the merchant NPC
        assert!(
            text1.contains("Greta"),
            "First visit should mention the merchant NPC. Got: {:?}",
            output1.text
        );

        // Deserialize updated state and verify merchant disposition is unchanged
        let state_after_visit1: GameState = serde_json::from_str(&output1.state_json).unwrap();
        let merchant_v1 = state_after_visit1.world.npcs.get(&merchant_npc_id).unwrap();
        assert_eq!(
            merchant_v1.disposition,
            state::Disposition::Friendly,
            "Merchant disposition should remain Friendly after first visit"
        );
        assert!(
            merchant_v1.combat_stats.is_none(),
            "Merchant should have no combat_stats after first visit"
        );

        // === Leave: Go South from B back to A ===
        let output_leave = process_input(&output1.state_json, "go south");
        let state_after_leave: GameState = serde_json::from_str(&output_leave.state_json).unwrap();
        assert_eq!(state_after_leave.current_location, room_a_id);

        // === Go to C: Go East from A to C ===
        let output_to_c = process_input(&output_leave.state_json, "go east");
        let state_after_c: GameState = serde_json::from_str(&output_to_c.state_json).unwrap();
        assert_eq!(state_after_c.current_location, room_c_id);

        // === Visit 2: Go North from C to B (alternate path) ===
        let output2 = process_input(&output_to_c.state_json, "go north");

        // Should NOT trigger combat on second visit either
        let text2 = output2.text.join(" ");
        assert!(
            !text2.contains("initiative") && !text2.contains("VICTORY") && !text2.contains("Your turn"),
            "Second visit via alternate path: merchant room should NOT trigger combat. Got: {:?}",
            output2.text
        );

        // Verify merchant disposition is STILL Friendly
        let state_after_visit2: GameState = serde_json::from_str(&output2.state_json).unwrap();
        let merchant_v2 = state_after_visit2.world.npcs.get(&merchant_npc_id).unwrap();
        assert_eq!(
            merchant_v2.disposition,
            state::Disposition::Friendly,
            "Merchant disposition should remain Friendly after second visit via alternate path"
        );
        assert!(
            merchant_v2.combat_stats.is_none(),
            "Merchant should have no combat_stats after second visit"
        );
        assert!(
            state_after_visit2.active_combat.is_none(),
            "No active combat should exist after visiting a Friendly merchant room"
        );
    }

    /// Find an RNG seed that produces a nat-20 on the first `roll_d20` call.
    fn find_nat20_seed() -> u64 {
        use rand::rngs::StdRng;
        use rand::SeedableRng;
        for seed in 0u64..100_000 {
            let mut rng = StdRng::seed_from_u64(seed);
            let roll = rules::dice::roll_d20(&mut rng);
            if roll == 20 {
                return seed;
            }
        }
        panic!("Could not find a seed that rolls nat-20 within 100k attempts");
    }

    #[test]
    fn test_nat20_death_save_gives_player_turn_prompt() {
        let mut state = create_test_combat_state();
        force_player_turn(&mut state);

        state.character.current_hp = 0;

        let nat20_seed = find_nat20_seed();
        state.rng_counter = 0;
        state.rng_seed = nat20_seed;

        let state_json = serde_json::to_string(&state).unwrap();
        let output = process_input(&state_json, "attack goblin");
        let new_state: GameState = serde_json::from_str(&output.state_json).unwrap();

        assert_eq!(
            new_state.character.current_hp, 1,
            "Nat-20 death save should revive player at 1 HP"
        );
        assert!(
            output.text.iter().any(|t| t.contains("regain 1 HP")),
            "Expected revival narration, got: {:?}",
            output.text
        );
        assert!(
            output.text.iter().any(|t| t.contains("Your turn!")),
            "After nat-20 revival, player should get a turn prompt. Got: {:?}",
            output.text
        );

        let combat = new_state.active_combat.as_ref().expect("Combat should still be active");
        assert!(
            combat.is_player_turn(),
            "Initiative should remain on the player after nat-20 revival"
        );
    }

    // ---- Death Saving Throw Accumulation (issue #227) ----

    /// Build a dying-in-combat `GameState` suitable for death save integration
    /// tests. The player is at 0 HP, it is the player's turn, and the NPC is
    /// placed 200 ft away with only a melee weapon (reach 5) so it will never
    /// attack the dying player during its turn.
    fn create_dying_combat_state() -> GameState {
        let mut state = create_test_exploration_state();

        // Place a goblin far from the player so it moves each NPC turn but
        // never attacks (melee reach 5 vs distance 200).
        let npc_id = 100;
        let loc_id = state.current_location;
        state.world.npcs.insert(npc_id, state::Npc {
            id: npc_id,
            name: "Distant Goblin".to_string(),
            role: state::NpcRole::Guard,
            disposition: state::Disposition::Hostile,
            dialogue_tags: vec![],
            location: loc_id,
            combat_stats: Some(state::CombatStats {
                max_hp: 7, current_hp: 7, ac: 15, speed: 30,
                ability_scores: {
                    let mut m = HashMap::new();
                    m.insert(Ability::Strength, 8);
                    m.insert(Ability::Dexterity, 14);
                    m
                },
                attacks: vec![state::NpcAttack {
                    name: "Scimitar".to_string(), hit_bonus: 4,
                    damage_dice: 1, damage_die: 6, damage_bonus: 2,
                    damage_type: state::DamageType::Slashing, reach: 5,
                    // No ranged capability
                    range_normal: 0, range_long: 0,
                }],
                proficiency_bonus: 2,
                cr: 0.25,
                ..Default::default()
            }),
            conditions: Vec::new(),
        });
        if let Some(loc) = state.world.locations.get_mut(&loc_id) {
            loc.npcs.push(npc_id);
        }

        // Give player a weapon (required for valid combat state).
        let weapon_id = 200;
        state.world.items.insert(weapon_id, state::Item {
            id: weapon_id,
            name: "Longsword".to_string(),
            description: "A fine longsword.".to_string(),
            item_type: state::ItemType::Weapon {
                damage_dice: 1, damage_die: 8,
                damage_type: state::DamageType::Slashing,
                properties: crate::equipment::VERSATILE,
                category: state::WeaponCategory::Martial,
                versatile_die: 10, range_normal: 0, range_long: 0,
            },
            location: None,
            carried_by_player: true,
            charges_remaining: None,
        });
        state.character.inventory.push(weapon_id);
        state.character.equipped.main_hand = Some(weapon_id);

        // Build combat with player first in initiative so we control the
        // death save timing precisely. NPC at distance 200.
        state.active_combat = Some(combat::CombatState {
            initiative_order: vec![
                (combat::Combatant::Player, 20),
                (combat::Combatant::Npc(npc_id), 5),
            ],
            round: 1,
            distances: {
                let mut d = HashMap::new();
                d.insert(npc_id, 200);
                d
            },
            player_movement_remaining: 30,
            ..Default::default()
        });

        // Drop the player to 0 HP (dying).
        state.character.current_hp = 0;

        state
    }

    /// Scan for an `rng_seed` value where the first three d20 rolls drawn
    /// from a single `StdRng::seed_from_u64(rng_seed + counter)` are all
    /// failures (d20 in 2..=9). This mirrors the engine's behavior: a single
    /// `process_input` call resolves multiple death save rounds using the
    /// same RNG instance.
    fn find_seed_three_consecutive_failures(base_counter: u64) -> u64 {
        use rand::Rng;
        for seed in 0u64..100_000 {
            let mut rng = StdRng::seed_from_u64(seed + base_counter);
            let all_fail = (0..3).all(|_| {
                let d20: i32 = rng.gen_range(1..=20);
                (2..=9).contains(&d20)
            });
            if all_fail {
                return seed;
            }
        }
        panic!("no seed found producing 3 consecutive failure rolls");
    }

    /// Scan for an `rng_seed` value where the first d20 drawn from
    /// `StdRng::seed_from_u64(rng_seed + counter)` is a natural 1.
    fn find_seed_nat_one(counter: u64) -> u64 {
        use rand::Rng;
        for seed in 0u64..100_000 {
            let mut rng = StdRng::seed_from_u64(seed + counter);
            let d20: i32 = rng.gen_range(1..=20);
            if d20 == 1 {
                return seed;
            }
        }
        panic!("no seed found producing a natural 1");
    }

    // Drives 3 separate process_input calls (one death save per call) with
    // failure-producing seeds and verifies the player is dead after the third.
    #[test]
    fn test_three_death_save_failures_across_process_input_triggers_game_over() {
        use rand::Rng;

        // Find three seeds that each produce a failure roll (d20 in 2..=9)
        // at counter 0 so we can control each call independently.
        let find_failure_seed = || -> u64 {
            for seed in 0u64..100_000 {
                let mut rng = StdRng::seed_from_u64(seed);
                let d20: i32 = rng.gen_range(1..=20);
                if (2..=9).contains(&d20) {
                    return seed;
                }
            }
            panic!("no failure seed found");
        };

        let failure_seed = find_failure_seed();
        let mut state = create_dying_combat_state();

        // Turn 1: one failure
        state.rng_seed = failure_seed;
        state.rng_counter = 0;
        let out1 = process_input(&serde_json::to_string(&state).unwrap(), "wait");
        let mut state: GameState = serde_json::from_str(&out1.state_json).unwrap();
        assert!(out1.text.join("\n").to_lowercase().contains("failure"), "Turn 1 should produce a failure");

        // Turn 2: second failure
        state.rng_seed = failure_seed;
        state.rng_counter = 0;
        let out2 = process_input(&serde_json::to_string(&state).unwrap(), "wait");
        let mut state: GameState = serde_json::from_str(&out2.state_json).unwrap();
        assert!(out2.text.join("\n").to_lowercase().contains("failure"), "Turn 2 should produce a failure");

        // Turn 3: third failure — should trigger death
        state.rng_seed = failure_seed;
        state.rng_counter = 0;
        let out3 = process_input(&serde_json::to_string(&state).unwrap(), "wait");
        let final_state: GameState = serde_json::from_str(&out3.state_json).unwrap();
        let text3 = out3.text.join("\n");

        assert!(
            final_state.active_combat.is_none(),
            "Combat should end after three failures. Output: {}",
            text3
        );
        assert!(
            final_state.character.current_hp <= 0,
            "Player HP should be 0 or below after death"
        );
        assert!(
            text3.contains("DEFEAT") || text3.to_lowercase().contains("fallen"),
            "Expected defeat narration, got: {}",
            text3
        );

        // GAME OVER gate: one more call should show GAME OVER.
        let out_go = process_input(&serde_json::to_string(&final_state).unwrap(), "look");
        assert!(
            out_go.text.join("\n").contains("GAME OVER"),
            "After defeat, process_input should show GAME OVER. Got: {:?}",
            out_go.text
        );
    }

    // Hypothesis: A natural 1 on a death save adds 2 failures per SRD. When
    // the character already has 2 accumulated failures, a nat-1 should push
    // the total to 3 (capped) and trigger death in a single `process_input`
    // call.
    #[test]
    fn test_nat_one_death_save_with_two_prior_failures_kills_instantly() {
        let mut state = create_dying_combat_state();
        let base_counter = state.rng_counter;

        // Pre-set 2 death save failures (as if accumulated from prior turns).
        if let Some(ref mut combat) = state.active_combat {
            combat.death_save_failures = 2;
        }

        // Find a seed that gives a natural 1.
        let seed = find_seed_nat_one(base_counter);
        state.rng_seed = seed;

        // Verify the d20 is indeed 1 at this seed + counter.
        {
            use rand::Rng;
            let mut rng = StdRng::seed_from_u64(seed + base_counter);
            let d20: i32 = rng.gen_range(1..=20);
            assert_eq!(d20, 1, "pre-check: expected nat-1, got {}", d20);
        }

        // One process_input call should kill the character.
        let json = serde_json::to_string(&state).unwrap();
        let out = process_input(&json, "wait");
        let final_state: GameState = serde_json::from_str(&out.state_json).unwrap();
        let text = out.text.join("\n");

        // Nat-1 adds 2 failures: 2 + 2 = 4, capped at 3 → Dead.
        assert!(
            final_state.active_combat.is_none(),
            "Combat should end after nat-1 with 2 pre-existing failures"
        );
        assert!(
            final_state.character.current_hp <= 0,
            "Player HP should remain at 0 or below"
        );
        assert!(
            text.contains("DEFEAT") || text.contains("fallen") || text.contains("died"),
            "Expected defeat narration, got: {}",
            text
        );

        // Confirm GAME OVER on next call.
        let out2 = process_input(&out.state_json, "look");
        let text2 = out2.text.join("\n");
        assert!(
            text2.contains("GAME OVER"),
            "After nat-1 death, process_input should show GAME OVER. Got: {}",
            text2
        );
    }

